import React, { useEffect, useMemo, useState } from 'react';
import './Projects.css';

const PROJECTS = [
  {
    id: 1,
    title: 'Reel 01',
    category: 'Video Edit',
    year: '2024',
    description: 'A cinematic edit showcasing storytelling through precise cuts and color.',
    driveId: '1CdmJQo2rkIx1YRf0q9W-iTnVRoTWDXB2',
    accent: 'blue',
  },
  {
    id: 2, title: 'Coming Soon', category: '', year: '',
    description: '', driveId: null, accent: 'pink',
  },
  {
    id: 3, title: 'Coming Soon', category: '', year: '',
    description: '', driveId: null, accent: 'lavender',
  },
];

const getAccentColor = (accent) => {
  if (accent === 'pink') return 'var(--pink)';
  if (accent === 'lavender') return 'var(--lavender)';
  return 'var(--blue)';
};

export default function Projects() {
  const [activeId, setActiveId] = useState(1);
  const [fading, setFading] = useState(false);

  const activeProject = useMemo(
    () => PROJECTS.find((project) => project.id === activeId) || PROJECTS[0],
    [activeId]
  );

  useEffect(() => {
    setFading(true);
    const timer = setTimeout(() => setFading(false), 150);
    return () => clearTimeout(timer);
  }, [activeId]);

  const accentColor = getAccentColor(activeProject.accent);

  return (
    <section className="projects-page">
      <p className="projects-label">Projects</p>
      <div className="projects-layout">
        <div className="featured-panel">
          <div className="project-eyebrow">
            <span className="category-badge" style={{ borderColor: accentColor, color: accentColor }}>
              {activeProject.category || 'Coming Soon'}
            </span>
            <span className="project-year">{activeProject.year || '--'}</span>
            <span className="project-title">{activeProject.title}</span>
          </div>

          <div className={`player-container ${fading ? 'player-fade' : ''}`}>
            <span className="player-glow" style={{ background: accentColor }} />
            {activeProject.driveId ? (
              <iframe
                src={`https://drive.google.com/file/d/${activeProject.driveId}/preview`}
                width="100%"
                height="100%"
                allow="autoplay; encrypted-media"
                allowFullScreen
                title={activeProject.title}
                style={{ border: 'none', position: 'absolute', inset: 0 }}
              />
            ) : (
              <div className="player-placeholder">
                <svg viewBox="0 0 40 40" aria-hidden="true">
                  <polygon points="12,8 32,20 12,32" />
                </svg>
                <p>Project coming soon</p>
              </div>
            )}
          </div>

          <p className="project-description">
            {activeProject.description || 'This slot is reserved for an upcoming cinematic project.'}
          </p>
        </div>

        <aside className="project-list-panel">
          <div className="list-head">
            <h2>Selected Work</h2>
            <p>{PROJECTS.length} projects</p>
          </div>

          <div className="project-list">
          {PROJECTS.map((project) => (
            <button
              className={`list-item ${project.id === activeId ? 'active' : ''} ${!project.driveId ? 'placeholder' : ''}`}
              key={project.id}
              type="button"
              onClick={() => project.driveId && setActiveId(project.id)}
            >
              <div className="list-top">
                <span className="list-title">{project.title}</span>
                <span className="list-year">{project.year || '--'}</span>
              </div>
              <div className="list-bottom">
                {project.driveId ? (
                  <span
                    className="mini-pill"
                    style={{
                      borderColor: getAccentColor(project.accent),
                      color: getAccentColor(project.accent),
                    }}
                  >
                    {project.category}
                  </span>
                ) : (
                  <span className="soon-tag">Soon</span>
                )}
              </div>
            </button>
          ))}
          </div>
        </aside>
        </div>
    </section>
  );
}
